class LRUCache {
private:
    struct Node {
        int key;
        int value;
        Node* prev;
        Node* next;
        Node(int k, int v) : key(k), value(v), prev(nullptr), next(nullptr) {}
    };
    Node* head;
    Node* tail;
    std::unordered_map<int, Node*> map;
    int capacity;
    int size;

public:
    LRUCache(int capacity) : capacity(capacity), size(0) {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }

    int get(int key) {
        auto it = map.find(key);
        if (it == map.end()) {
            return -1;
        }
        Node* node = it->second;
        if (node != head->next) {
            node->prev->next = node->next;
            node->next->prev = node->prev;
            node->prev = head;
            node->next = head->next;
            head->next->prev = node;
            head->next = node;
        }
        return node->value;
    }

    void put(int key, int value) {
        auto it = map.find(key);
        if (it != map.end()) {
            Node* node = it->second;
            node->value = value;
            if (node != head->next) {
                node->prev->next = node->next;
                node->next->prev = node->prev;
                node->prev = head;
                node->next = head->next;
                head->next->prev = node;
                head->next = node;
            }
            return;
        } else {
            if (size + 1 > capacity) {
                Node* tail_node = tail->prev;
                map.erase(tail_node->key);
                if (tail_node->prev) {
                    tail_node->prev->next = tail;
                }
                tail->prev = tail_node->prev;
                delete tail_node;
                size--;
            }
            Node* new_node = new Node(key, value);
            new_node->prev = head;
            new_node->next = head->next;
            head->next->prev = new_node;
            head->next = new_node;
            map[key] = new_node;
            size++;
        }
    }
};

